/*
 * acosf() test harness -- prints (input_hex, output_hex) pairs.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly acosf  (test_acosf_opt.elf)
 *   2. Linked with toolchain's default acosf        (test_acosf_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
#endif

static inline uint32_t f2u(float f)
{
    union { float f; uint32_t u; } x;
    x.f = f;
    return x.u;
}

static inline float u2f(uint32_t u)
{
    union { float f; uint32_t u; } x;
    x.u = u;
    return x.f;
}

#ifdef EN_PERF
static volatile float g_acc;

static void emit(float x)
{
    volatile float vx = x;  /* prevent constant-folding of literal arguments */
    g_acc += acosf(vx);
}

static void emit_u(uint32_t bits)
{
    emit(u2f(bits));
}
#else
static void emit(float x)
{
    float r = acosf(x);
    printf("%08lx %08lx\n", (unsigned long)f2u(x), (unsigned long)f2u(r));
}

static void emit_u(uint32_t bits)
{
    emit(u2f(bits));
}
#endif

/* ------------------------------------------------------------------ */
/* Representative 100-point test suite                                */
/* ------------------------------------------------------------------ */

static void test_representative_100(void)
{
    /* --- Section 1: Special IEEE 754 values (7) --- */
    emit(0.0f);                       /* acos(0) = pi/2 */
    emit(-0.0f);                      /* acos(-0) = pi/2 */
    emit_u(0x7fc00000u);              /* qNaN */
    emit_u(0x7f800001u);              /* sNaN */
    emit_u(0xffc00000u);              /* -qNaN */
    emit_u(0x7f800000u);              /* +Inf: out of domain -> NaN */
    emit_u(0xff800000u);              /* -Inf: out of domain -> NaN */

    /* --- Section 2: Subnormal (denormal) values (6) --- */
    /* All near 0; acos(x) ~ pi/2 - x for tiny x */
    emit_u(0x00000001u);              /* min positive subnormal: 2^-149 */
    emit_u(0x80000001u);              /* min negative subnormal */
    emit_u(0x00400000u);              /* mid positive subnormal */
    emit_u(0x80400000u);              /* mid negative subnormal */
    emit_u(0x007fffffu);              /* max positive subnormal */
    emit_u(0x807fffffu);              /* max negative subnormal */

    /* --- Section 3: Normal boundary values (4) --- */
    emit(FLT_MIN);                    /* 2^-126, smallest normal; acos ~ pi/2 */
    emit(-FLT_MIN);                   /* negative smallest normal */
    emit_u(0x00800001u);              /* one ULP above FLT_MIN */
    emit_u(0x807ffffeu);              /* one ULP below -FLT_MIN (toward -FLT_MIN) */

    /* --- Section 4: Near +1.0 and -1.0 (domain endpoints) ULP density (8) --- */
    emit_u(0x3f7fffffu);              /* 1.0 - 1 ULP: last valid positive input */
    emit(1.0f);                       /* 1.0 exactly: acos(1) = 0 */
    emit_u(0x3f800001u);              /* 1.0 + 1 ULP: just outside domain -> NaN */
    emit_u(0x3f7ffffeu);              /* 1.0 - 2 ULP */
    emit_u(0xbf7fffffu);              /* -1.0 + 1 ULP: last valid negative input */
    emit(-1.0f);                      /* -1.0 exactly: acos(-1) = pi */
    emit_u(0xbf800001u);              /* -1.0 - 1 ULP: just outside domain -> NaN */
    emit_u(0xbf7ffffeu);              /* -1.0 + 2 ULP */

    /* --- Section 5: Exponent switching points near 0.5 and 0.25 (6) --- */
    emit_u(0x3efffffeu);              /* 0.5 - 2 ULP */
    emit_u(0x3effffffu);              /* 0.5 - 1 ULP */
    emit(0.5f);                       /* 0.5: acos(0.5) = pi/3 */
    emit_u(0x3f000001u);              /* 0.5 + 1 ULP */
    emit(-0.5f);                      /* -0.5: acos(-0.5) = 2pi/3 */
    emit_u(0xbf000001u);              /* -0.5 - 1 ULP (more negative) */

    /* --- Section 6: Key mathematical values (14) --- */
    /* acos(sqrt(3)/2) = pi/6 = 30 deg */
    emit(0.86602540378443864676f);    /* sqrt(3)/2 */
    emit(-0.86602540378443864676f);   /* -sqrt(3)/2: acos = 5pi/6 */
    /* acos(sqrt(2)/2) = pi/4 = 45 deg */
    emit(0.70710678118654752440f);    /* sqrt(2)/2 */
    emit(-0.70710678118654752440f);   /* -sqrt(2)/2: acos = 3pi/4 */
    /* acos(1/3) ~ 70.5 deg */
    emit(0.33333333333333333333f);    /* 1/3 */
    emit(-0.33333333333333333333f);   /* -1/3: acos = ~109.5 deg */
    /* acos(2/3) ~ 48.19 deg */
    emit(0.66666666666666666667f);    /* 2/3 */
    emit(-0.66666666666666666667f);   /* -2/3 */
    /* acos(0.9) ~ 25.84 deg */
    emit(0.9f);
    emit(-0.9f);
    /* acos(0.1) ~ 84.26 deg */
    emit(0.1f);
    emit(-0.1f);
    /* acos(-0.5) = 2*pi/3 boundary */
    emit(0.25f);                      /* acos(0.25) ~ 75.52 deg */
    emit(-0.25f);

    /* --- Section 7: Out-of-domain inputs (6) --- */
    /* All should return NaN */
    emit(1.5f);                       /* just outside +1 */
    emit(-1.5f);                      /* just outside -1 */
    emit(2.0f);
    emit(-2.0f);
    emit(FLT_MAX);                    /* huge positive */
    emit(-FLT_MAX);                   /* huge negative */

    /* --- Section 8: ULP triplets at domain endpoints (12) --- */
    /* Around 1.0 */
    emit_u(0x3f7ffffdу);              /* 1.0 - 3 ULP */
    emit_u(0x3f7ffffcu);              /* 1.0 - 4 ULP */
    emit_u(0x3f7ffff0u);              /* 1.0 - 16 ULP */
    emit_u(0x3f7fff80u);              /* 1.0 - 128 ULP */
    emit_u(0x3f7ffe00u);              /* 1.0 - 512 ULP */
    emit_u(0x3f7ff800u);              /* 1.0 - 2048 ULP */
    /* Around -1.0 */
    emit_u(0xbf7ffffdу);              /* -1.0 + 3 ULP */
    emit_u(0xbf7ffffcu);              /* -1.0 + 4 ULP */
    emit_u(0xbf7ffff0u);              /* -1.0 + 16 ULP */
    emit_u(0xbf7fff80u);              /* -1.0 + 128 ULP */
    emit_u(0xbf7ffe00u);              /* -1.0 + 512 ULP */
    emit_u(0xbf7ff800u);              /* -1.0 + 2048 ULP */

    /* --- Section 9: Near 0.5 polynomial branch transition (9) --- */
    /* Many acos implementations switch algorithm at |x| = 0.5 */
    emit_u(0x3f000010u);              /* 0.5 + 16 ULP */
    emit_u(0x3f000100u);              /* 0.5 + 256 ULP */
    emit_u(0x3f001000u);              /* 0.5 + 4096 ULP */
    emit_u(0x3effffc0u);              /* 0.5 - 64 ULP */
    emit_u(0x3effff00u);              /* 0.5 - 256 ULP */
    emit_u(0xbf000010u);              /* -0.5 - 16 ULP (more negative) */
    emit_u(0xbf000100u);              /* -0.5 - 256 ULP */
    emit_u(0xbeffffc0u);              /* -0.5 + 64 ULP (toward zero) */
    emit_u(0xbeffff00u);              /* -0.5 + 256 ULP (toward zero) */

    /* --- Section 10: Dense coverage of [-1, 1] interior (28) --- */
    /* Evenly spaced across the domain to cover polynomial evaluation */
    emit(-0.95f);
    emit(-0.85f);
    emit(-0.75f);
    emit(-0.65f);
    emit(-0.55f);
    emit(-0.45f);
    emit(-0.35f);
    emit(-0.15f);
    emit(-0.05f);
    emit(0.05f);
    emit(0.15f);
    emit(0.35f);
    emit(0.45f);
    emit(0.55f);
    emit(0.65f);
    emit(0.75f);
    emit(0.85f);
    emit(0.95f);
    /* Additional coverage near sqrt(2)/2 and sqrt(3)/2 transitions */
    emit_u(0x3f3504f3u);              /* sqrt(2)/2 exact float */
    emit_u(0x3f3504f4u);              /* sqrt(2)/2 + 1 ULP */
    emit_u(0x3f3504f2u);              /* sqrt(2)/2 - 1 ULP */
    emit_u(0xbf3504f3u);              /* -sqrt(2)/2 exact float */
    emit_u(0x3f6ed9ebu);              /* sqrt(3)/2 approx */
    emit_u(0x3f6ed9ecu);              /* sqrt(3)/2 + 1 ULP */
    emit_u(0xbf6ed9ebu);              /* -sqrt(3)/2 approx */
    emit(0.8f);
    emit(-0.8f);
}

/* ------------------------------------------------------------------ */

/* 7. Sweep [-1, 1] in 200 steps */
#ifndef EN_PERF
static void test_sweep(void)
{
    int nsteps = 200;
    for (int i = 0; i <= nsteps; i++)
        emit(-1.0f + 2.0f * (float)i / (float)nsteps);
}

/* 8. Exhaustive [-1, 1] every 65536 ULP */
static void test_exhaustive_small(void)
{
    uint32_t start = 0xbf800000u; /* -1.0 */
    uint32_t end   = 0x3f800000u; /*  1.0 */
    for (uint32_t b = start; b <= end; b += 65536) {
        if (b >= start && b <= end)
            emit_u(b);
    }
}
#endif

/* ------------------------------------------------------------------ */

int main(void)
{
#ifdef EN_PERF
    startPFM;
    test_representative_100();
    stopPFM;
    readResult();
    printf("perf acc: %08lx\n", (unsigned long)f2u((float)g_acc));
#else
    test_representative_100();
    test_sweep();
    test_exhaustive_small();
#endif
    return 0;
}

